sql:
SELECT activity_id, COUNT(viewpoint_id) AS number_of_viewpoints
FROM viewpoints
GROUP BY activity_id;

external_knowledge:
- Popularity is measured by the average rating derived from user feedback;
- User feedback is categorized into agreement and disagreement responses;
- Activities are ranked based on their overall popularity.

sql:
SELECT COUNT(response_id) AS positive_responses_count
FROM responses
WHERE response_type_id = 1;

SELECT category_name
FROM categories
WHERE category_id = 1;

SELECT COUNT(response_id) AS response_count
FROM responses
WHERE viewpoint_id = 0;

SELECT viewpoint_id, viewpoint_text, created_at
FROM viewpoints
ORDER BY created_at DESC;

SELECT COUNT(DISTINCT user_id) AS unique_user_count
FROM viewpoints
WHERE activity_id = 1;

SELECT COUNT(DISTINCT user_id) AS number_of_unique_users
FROM viewpoints
WHERE activity_id = 1;

SELECT AVG(activity_rating) AS average_rating
FROM activities
WHERE is_active = 1;
